use anyhow::Result;
use dialoguer::{Input, Select};

/// Prompt for text input with a label.
/// Returns `Err` if stdin is not a TTY (caller should handle non-interactive error).
pub fn prompt_input<T: std::fmt::Display>(
    prompt: &str,
    default: Option<&str>,
) -> Result<String> {
    let mut builder = Input::<String>::new();
    builder.with_prompt(prompt);
    if let Some(d) = default {
        builder.default(d);
    }
    builder.interact_text().map_err(Into::into)
}

/// Prompt for a selection from a list.
/// Returns the selected index.
pub fn prompt_select(items: &[&str], prompt: &str) -> Result<usize> {
    let selection = Select::new()
        .with_prompt(prompt)
        .items(items)
        .interact()?;
    Ok(selection)
}

/// Prompt for a yes/no confirmation.
/// Returns `true` if the user confirms.
pub fn prompt_confirm(prompt: &str) -> Result<bool> {
    use dialoguer::Confirm;
    let confirmed = Confirm::new()
        .with_prompt(prompt)
        .default(false)
        .interact()?;
    Ok(confirmed)
}

/// Check if stdin is a TTY (interactive).
pub fn is_interactive() -> bool {
    atty::is(atty::Stream::Stdin)
}

use crate::core::BoardState;

/// Current mode of the TUI.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Mode {
    Normal,
    Insert,
    Edit,
    Column,
    Confirm,
    Help,
    Move,
}

impl std::fmt::Display for Mode {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Mode::Normal => write!(f, "NORMAL"),
            Mode::Insert => write!(f, "INSERT"),
            Mode::Edit => write!(f, "EDIT"),
            Mode::Column => write!(f, "COLUMN"),
            Mode::Confirm => write!(f, "CONFIRM"),
            Mode::Help => write!(f, "HELP"),
            Mode::Move => write!(f, "MOVE"),
        }
    }
}

/// Possible actions resulting from input handling.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    None,
    Quit,
    ModeChange(Mode),
    NavigatePrevColumn,
    NavigateNextColumn,
    NavigatePrevTask,
    NavigateNextTask,
    AddTask,
    EditTask,
    DeleteTask,
    EnterMoveMode,
    MoveTaskPrevColumn,
    MoveTaskNextColumn,
    MoveTaskDown,
    MoveTaskUp,
    EnterColumnMode,
    ToggleHelp,
    // Move mode actions
    MoveConfirm,
    MoveCancel,
    // Column mode actions
    ColumnAdd,
    ColumnRename,
    ColumnDelete,
    ColumnMoveLeft,
    ColumnMoveRight,
    ColumnExit,
    // Insert/Edit actions
    Save,
    Cancel,
    CycleField,
    InsertText(String),
    DeleteChar,
    ConfirmYes,
    ConfirmNo,
}

/// The TUI application state.
pub struct App {
    pub state: Option<BoardState>,
    pub mode: Mode,
    /// Index into the current column's tasks.
    pub focused_col_idx: usize,
    pub focused_task_idx: usize,
    pub error: Option<String>,
    pub error_tick: u64,
    pub tick: u64,
    /// Text buffer for insert/edit modes.
    pub input_buffer: String,
    pub cursor_pos: usize,
    /// For edit mode: which field is being edited (0=title, 1=description, 2=priority).
    pub edit_field: usize,
    /// The task being edited (if any).
    pub editing_task: Option<crate::core::Task>,
    /// Pending delete task ID.
    pub delete_task_id: Option<String>,
    /// For move mode: the highlighted destination column index.
    pub move_target_col_idx: usize,
}

impl App {
    pub fn new() -> Self {
        Self {
            state: None,
            mode: Mode::Normal,
            focused_col_idx: 0,
            focused_task_idx: 0,
            error: None,
            error_tick: 0,
            tick: 0,
            input_buffer: String::new(),
            cursor_pos: 0,
            edit_field: 0,
            editing_task: None,
            delete_task_id: None,
            move_target_col_idx: 0,
        }
    }

    pub fn with_state(state: BoardState) -> Self {
        let mut app = Self::new();
        app.state = Some(state);
        app
    }

    pub fn set_error(&mut self, msg: String) {
        self.error = Some(msg);
        self.error_tick = self.tick;
    }

    pub fn clear_error(&mut self) {
        self.error = None;
    }

    /// Get the focused column, if any.
    pub fn focused_column(&self) -> Option<&crate::core::Column> {
        self.state
            .as_ref()
            .and_then(|s| s.columns.get(self.focused_col_idx))
    }

    /// Get the tasks in the focused column.
    pub fn focused_column_tasks(&self) -> Vec<&crate::core::Task> {
        let col = match self.focused_column() {
            Some(c) => &c.id,
            None => return vec![],
        };
        self.state
            .as_ref()
            .map(|s| {
                s.tasks
                    .iter()
                    .filter(|t| t.column_id == *col)
                    .collect()
            })
            .unwrap_or_default()
    }

    /// Get the currently focused task.
    pub fn focused_task(&self) -> Option<&crate::core::Task> {
        let tasks = self.focused_column_tasks();
        tasks.get(self.focused_task_idx)
    }

    pub fn clamp_focus(&mut self) {
        if let Some(ref state) = self.state {
            self.focused_col_idx = self.focused_col_idx.min(state.columns.len().saturating_sub(1));
            let tasks = self.focused_column_tasks();
            self.focused_task_idx = self.focused_task_idx.min(tasks.len().saturating_sub(1));
        }
    }

    pub fn tick(&mut self) {
        self.tick += 1;
        // Clear error after ~3 seconds (assuming 20 ticks/sec)
        if self.error.is_some() && (self.tick - self.error_tick) > 60 {
            self.clear_error();
        }
    }
}

use ratatui::style::{Color, Modifier, Style};
use ratatui::text::Span;

use crate::core::min_unique_prefixes;

use super::app::App;

/// Compute the styled spans for a task's short ID (jj-style).
///
/// The minimum-unique prefix is rendered in bold/bright, the remainder in dim.
pub fn render_task_id_spans(task_id: &str, min_len: usize) -> Vec<Span> {
    let parts: Vec<&str> = task_id.split_at(min_len).to_vec();
    vec![
        Span::styled(
            parts[0].to_string(),
            Style::default().add_modifier(Modifier::BOLD).fg(Color::Cyan),
        ),
        Span::styled(
            parts[1].to_string(),
            Style::default().dim(),
        ),
    ]
}

/// Build the set of visible task IDs for computing min-unique prefixes.
pub fn get_visible_task_ids(app: &App) -> Vec<&str> {
    app.state
        .as_ref()
        .map(|s| s.tasks.iter().map(|t| t.id.as_str()).collect())
        .unwrap_or_default()
}

/// Get the minimum prefix lengths for all visible tasks, as a map.
pub fn get_min_prefix_lengths(app: &App) -> std::collections::HashMap<String, usize> {
    let ids = get_visible_task_ids(app);
    let prefixes = min_unique_prefixes(&ids);
    prefixes
        .into_iter()
        .map(|(id, len)| (id, len))
        .collect()
}

