pub fn render_task_id_spans(task_id: &str, min_len: usize) -> Vec<Span> {
    let (prefix, rest) = task_id.split_at(min_len);
    let parts = vec![prefix, rest];
    vec![
        Span::styled(
            parts[0].to_string(),
            Style::default().add_modifier(Modifier::BOLD).fg(Color::Cyan),
        ),
        Span::styled(
            parts[1].to_string(),
            Style::default().dim(),
        ),
    ]
}

